const express = require('express');
const app = express();
const sendgrid = require('@sendgrid/mail');
const twilio = require('twilio');

// Set up SendGrid and Twilio credentials
const sendgridApiKey = process.env.SENDGRID_API_KEY;
const twilioAccountSid = process.env.TWILIO_ACCOUNT_SID;
const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;

// Set up SendGrid and Twilio clients
sendgrid.setApiKey(sendgridApiKey);
const sendgridClient = new sendgrid.MailService();
twilio.initialize(twilioAccountSid, twilioAuthToken);
const twilioClient = new twilio.RestClient();

// Define a function to handle message delivery
async function deliverMessage(message) {
  // Check if the message is an email or SMS
  const isEmail = message.to.includes('@');
  let client;
  if (isEmail) {
    client = sendgridClient;
  } else {
    client = twilioClient;
  }

  // Set up the message data
  const msgData = {
    from: 'your-email@example.com',
    to: message.to,
    subject: message.subject,
    text: message.text,
  };

  // Send the message
  try {
    await client.send(msgData);
    console.log(`Message sent successfully`);
  } catch (err) {
    console.error(`Error sending message: ${err}`);
  }
}

// Define a route for handling incoming messages
app.post('/message', async (req, res) => {
  // Get the message data from the request body
  const message = req.body;

  // Deliver the message using the appropriate client
  await deliverMessage(message);

  // Respond with a success message
  res.json({ message: 'Message delivered successfully' });
});

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});